// ============================================================
//  BETSTAT — PROTEÇÃO COMPLETA (Anti-Scraping + DevTools)
//  Adicione no final do <body>, antes de </body>:
//  <script src="protecao.js"></script>
//
//  Após ajustes, ofusque com:
//  npx javascript-obfuscator protecao.js --output protecao.min.js \
//    --compact true --string-array true \
//    --rotate-string-array true --self-defending true
// ============================================================

(function () {

  // ============================================================
  // 1. BLOQUEIA CLIQUE DIREITO
  // ============================================================
  document.addEventListener("contextmenu", function (e) {
    e.preventDefault();
  });


  // ============================================================
  // 2. BLOQUEIA ATALHOS DE TECLADO
  //    DevTools: F12, Ctrl+Shift+I/J/C, Ctrl+U
  //    Salvar e imprimir: Ctrl+S, Ctrl+P
  // ============================================================
  document.addEventListener("keydown", function (e) {
    if (e.key === "F12")                             { e.preventDefault(); }
    if (e.ctrlKey && e.shiftKey && e.key === "I")    { e.preventDefault(); }
    if (e.ctrlKey && e.shiftKey && e.key === "J")    { e.preventDefault(); }
    if (e.ctrlKey && e.shiftKey && e.key === "C")    { e.preventDefault(); }
    if (e.ctrlKey && e.key === "u")                  { e.preventDefault(); }
    if (e.ctrlKey && e.key === "s")                  { e.preventDefault(); }
    if (e.ctrlKey && e.key === "p")                  { e.preventDefault(); }
  });


  // ============================================================
  // 3. IMPEDE ARRASTAR ELEMENTOS E SELECIONAR TEXTO
  // ============================================================
  document.addEventListener("dragstart",    function (e) { e.preventDefault(); });
  document.addEventListener("selectstart",  function (e) { e.preventDefault(); });


  // ============================================================
  // 4. SILENCIA O CONSOLE
  //    Dificulta inspeção de logs mesmo se DevTools for aberto.
  // ============================================================
  console.log   = function () {};
  console.debug = function () {};
  console.info  = function () {};
  console.warn  = function () {};


  // ============================================================
  // 5. UTILITÁRIO — TELA DE BLOQUEIO
  //    Centraliza o HTML de erro. _bloqueado declarado aqui,
  //    única vez, válido em todo o script.
  // ============================================================
  let _bloqueado = false;

  function _bloquearPagina(titulo, mensagem) {
    if (_bloqueado) return;
    _bloqueado = true;
    document.body.innerHTML = `
      <div style="
        display:flex;flex-direction:column;align-items:center;
        justify-content:center;height:100vh;background:#0a0f14;
        color:#1fac89;font-family:sans-serif;text-align:center;gap:16px;">
        <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="#1fac89" stroke-width="2">
          <circle cx="12" cy="12" r="10"/>
          <line x1="12" y1="8" x2="12" y2="12"/>
          <line x1="12" y1="16" x2="12.01" y2="16"/>
        </svg>
        <h2 style="margin:0;color:#fff;">${titulo}</h2>
        <p style="margin:0;color:#aaa;font-size:14px;">${mensagem}</p>
      </div>`;
  }


  // ============================================================
  // 6. DETECÇÃO DE DEVTOOLS — TRÊS TÉCNICAS COMBINADAS
  //
  //  A) Tamanho de janela (corrigida para mobile e zoom)
  //  B) Truque do Image getter — detecção via console.log
  //  C) Debugger timestamp — pega DevTools aberto antes da página
  // ============================================================
  let _devtoolsAberto = false;
  const _isMobile = /Mobi|Android|iPhone|iPad/i.test(navigator.userAgent);

  // — A) Tamanho de janela —
  const DEVTOOLS_THRESHOLD = 200;
  let _baseW    = window.outerWidth  - window.innerWidth;
  let _baseH    = window.outerHeight - window.innerHeight;
  let _zoomBase = window.devicePixelRatio || 1;

  function _checarDevToolsTamanho() {
    if (_isMobile) return;
    const zoomAtual = window.devicePixelRatio || 1;
    if (Math.abs(zoomAtual - _zoomBase) > 0.05) {
      _baseW    = window.outerWidth  - window.innerWidth;
      _baseH    = window.outerHeight - window.innerHeight;
      _zoomBase = zoomAtual;
      return;
    }
    const diffW = (window.outerWidth  - window.innerWidth)  - _baseW;
    const diffH = (window.outerHeight - window.innerHeight) - _baseH;
    if (diffW > DEVTOOLS_THRESHOLD || diffH > DEVTOOLS_THRESHOLD) {
      _devtoolsAberto = true;
    }
  }

  window.addEventListener('resize', _checarDevToolsTamanho, { passive: true });
  setInterval(_checarDevToolsTamanho, 500);

  // — B) Image getter —
  const _imgTrap = new Image();
  Object.defineProperty(_imgTrap, 'id', {
    get: function () { _devtoolsAberto = true; }
  });
  setInterval(function () {
    _devtoolsAberto;
    console.log('%c', _imgTrap); // eslint-disable-line no-console
  }, 1000);

  // — C) Debugger timestamp —
  if (!_isMobile) {
    (function () {
      const t0 = Date.now();
      debugger;
      if (Date.now() - t0 > 500) { _devtoolsAberto = true; }
    })();
  }


  // ============================================================
  // 7. AÇÃO QUANDO DEVTOOLS É DETECTADO
  // ============================================================
  setInterval(function () {
    if (_devtoolsAberto && !_bloqueado) {
      _bloquearPagina(
        'Acesso restrito',
        'As ferramentas de desenvolvedor estão bloqueadas nesta página.'
      );
    }
  }, 1000);


  // ============================================================
  // 8. DETECÇÃO DE BOT / SCRAPER HEADLESS
  // ============================================================
  (function _checarBot() {
    const ua = (navigator.userAgent || '').toLowerCase();
    const uasSuspeitos = [
      'headlesschrome', 'phantomjs', 'selenium', 'webdriver',
      'puppeteer', 'playwright', 'python-requests',
      'python-urllib', 'axios/', 'curl/', 'wget/', 'java/',
      'go-http-client', 'ruby', 'scrapy'
    ];
    if (uasSuspeitos.some(bot => ua.includes(bot))) {
      _bloquearPagina('Acesso negado', 'Acesso negado.');
      return;
    }
    if (navigator.webdriver === true) {
      _bloquearPagina('Acesso negado', 'Acesso negado.');
      return;
    }
    if (!navigator.languages || navigator.languages.length === 0) {
      _bloquearPagina('Acesso negado', 'Acesso negado.');
      return;
    }
  })();


  // ============================================================
  // 9. DETECÇÃO DE COMPORTAMENTO HUMANO
  // ============================================================
  let _humanoConfirmado = false;
  let _humanoResolve    = null;
  const _humanoPromise  = new Promise((resolve) => { _humanoResolve = resolve; });

  function _confirmarHumano() {
    if (!_humanoConfirmado) {
      _humanoConfirmado = true;
      _humanoResolve(true);
    }
  }

  ['mousemove', 'mousedown', 'keydown', 'touchstart', 'scroll', 'click'].forEach(evt => {
    window.addEventListener(evt, _confirmarHumano, { once: true, passive: true });
  });


  // ============================================================
  // 10. RATE LIMITING NO FRONTEND
  // ============================================================
  const _rateLimit = {
    janela: 60 * 1000,
    maxRequisicoes: 300,
    historico: [],
    podeFazerRequisicao() {
      const agora = Date.now();
      this.historico = this.historico.filter(ts => agora - ts < this.janela);
      if (this.historico.length >= this.maxRequisicoes) return false;
      this.historico.push(agora);
      return true;
    }
  };


  // ============================================================
  // 11. INTERCEPTADOR ÚNICO DE FETCH
  // ============================================================
  const _fetchOriginal      = window.fetch.bind(window);
  const _janelaSuspeita     = 2000;
  const _maxRapidas         = 30;
  let   _requisicoesRapidas = [];

  function _checarVelocidade() {
    const agora = Date.now();
    _requisicoesRapidas = _requisicoesRapidas.filter(ts => agora - ts < _janelaSuspeita);
    _requisicoesRapidas.push(agora);
    if (_requisicoesRapidas.length > _maxRapidas) {
      _bloquearPagina('Acesso bloqueado', 'Comportamento suspeito detectado.');
      throw new Error('Comportamento suspeito detectado.');
    }
  }

  window.fetch = async function (url, opcoes = {}) {
    const ehInterna = typeof url === 'string' && (
      url.includes('/api/') ||
      url.includes('betstat') ||
      url.startsWith('/')
    );
    if (!ehInterna) return _fetchOriginal(url, opcoes);
    _checarVelocidade();
    const confirmado = await Promise.race([
      _humanoPromise,
      new Promise(r => setTimeout(() => r(false), 8000))
    ]);
    if (!confirmado && !_humanoConfirmado) {
      throw new Error('Interação humana necessária.');
    }
    if (!_rateLimit.podeFazerRequisicao()) {
      throw new Error('Muitas requisições. Aguarde alguns segundos.');
    }
    return _fetchOriginal(url, opcoes);
  };


  // ============================================================
  // 12. BLOQUEIA CLIQUE DO MEIO DO MOUSE
  // ============================================================
  document.addEventListener("auxclick", function (e) {
    if (e.button === 1) e.preventDefault();
  });

})();